import sys
input = sys.stdin.readline

def main():
    q = int(input())
    queries = []

    for _ in range(q):
        line = input().split()
        if line[0] == '1':
            queries.append((1, int(line[1])))
        else:
            queries.append((2, int(line[1]), int(line[2])))

    remap = list(range(500001))

    def find(v):
        while remap[v] != v:
            remap[v] = remap[remap[v]]
            v = remap[v]
        return v

    # Process in reverse
    result = []
    for i in range(q - 1, -1, -1):
        query = queries[i]
        if query[0] == 1:
            result.append(find(query[1]))
        else:
            x, y = query[1], query[2]
            # x should map to whatever y maps to
            ry = find(y)
            rx = find(x)
            if rx != ry:
                remap[rx] = ry

    result.reverse()
    print(*result)

main()

